function perpus_circ_active_detail(mysqli $conn, int $detailId=0, string $barcode=''): ?array
{
    $sql = "SELECT d.*,e.barcode,b.judul,p.anggota_id,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,
        COALESCE(tm.maksimal_perpanjangan,1) maksimal_perpanjangan,COALESCE(tm.hari_perpanjangan,7) hari_perpanjangan
        FROM perpus_peminjaman_detail d
        JOIN perpus_peminjaman p ON p.id=d.peminjaman_id
        JOIN perpus_anggota a ON a.id=p.anggota_id
        LEFT JOIN perpus_tipe_member tm ON tm.id=a.tipe_member_id
        LEFT JOIN perpus_buku_eksemplar e ON e.id=d.eksemplar_id
        LEFT JOIN perpus_buku b ON b.id=d.buku_id
        WHERE d.status='dipinjam' AND ";
    if ($detailId > 0) {
        $stmt=$conn->prepare($sql.'d.id=? LIMIT 1 FOR UPDATE'); $stmt->bind_param('i',$detailId);
    } else {
        $stmt=$conn->prepare($sql.'(e.barcode=? OR d.kode_resi=?) ORDER BY d.id DESC LIMIT 1 FOR UPDATE'); $stmt->bind_param('ss',$barcode,$barcode);
    }
    $stmt->execute(); $row=$stmt->get_result()->fetch_assoc()?:null; $stmt->close(); return $row;
}
function perpus_circ_days_late(?string $dueDate): int
{
    if (!$dueDate) return 0; $today=new DateTimeImmutable('today'); $due=new DateTimeImmutable($dueDate); return $today>$due?(int)$due->diff($today)->days:0;
}

