            $stmt=$conn->prepare("INSERT INTO perpus_peminjaman_detail (peminjaman_id,buku_id,eksemplar_id,kode_resi,tanggal_jatuh_tempo,denda_awal,denda,status,denda_status) VALUES (?,?,?,?,?,?,0,'dipinjam','belum_lunas')");$stmt->bind_param('iiissd',$loanId,$bookId,$copyId,$bookCode,$due,$fine);$stmt->execute();$newDetailId=(int)$conn->insert_id;$stmt->close();
