$activeRows=[];$result=$conn->query("SELECT d.id,d.tanggal_jatuh_tempo,d.denda_awal,d.jumlah_perpanjangan,p.tanggal_pinjam,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul,e.barcode,COALESCE(tm.maksimal_perpanjangan,1) maksimal_perpanjangan,COALESCE(tm.hari_perpanjangan,7) hari_perpanjangan FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id JOIN perpus_anggota a ON a.id=p.anggota_id LEFT JOIN perpus_tipe_member tm ON tm.id=a.tipe_member_id LEFT JOIN perpus_buku b ON b.id=d.buku_id LEFT JOIN perpus_buku_eksemplar e ON e.id=d.eksemplar_id WHERE d.status='dipinjam' ORDER BY d.tanggal_jatuh_tempo ASC,d.id DESC LIMIT 300");while($result&&($r=$result->fetch_assoc())){$r['profile']=sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)$r['pemilik_id'],$r);$r['days_late']=perpus_circ_days_late($r['tanggal_jatuh_tempo']);$r['fine_estimate']=$r['days_late']*(float)$r['denda_awal'];$activeRows[]=$r;}
$fineRows=[];$result=$conn->query("SELECT d.id,d.denda,d.denda_status,d.tanggal_kembali,d.kondisi_kembali,p.anggota_id,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul,e.barcode,COALESCE((SELECT SUM(x.nominal) FROM perpus_denda_pembayaran x WHERE x.detail_id=d.id),0) dibayar FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id JOIN perpus_anggota a ON a.id=p.anggota_id LEFT JOIN perpus_buku b ON b.id=d.buku_id LEFT JOIN perpus_buku_eksemplar e ON e.id=d.eksemplar_id WHERE d.status<>'dipinjam' AND d.denda>0 AND d.denda_status='belum_lunas' ORDER BY d.tanggal_kembali DESC LIMIT 200");while($result&&($r=$result->fetch_assoc())){$r['profile']=sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)$r['pemilik_id'],$r);$r['sisa']=max(0,(float)$r['denda']-(float)$r['dibayar']);$fineRows[]=$r;}
$stats=['aktif'=>count($activeRows),'terlambat'=>0,'hari_ini'=>0,'denda'=>0,'tunggakan'=>0];foreach($activeRows as $r){if($r['days_late']>0){$stats['terlambat']++;$stats['denda']+=(float)$r['fine_estimate'];}if($r['tanggal_pinjam']===date('Y-m-d'))$stats['hari_ini']++;}foreach($fineRows as $r)$stats['tunggakan']+=(float)$r['sisa'];
