<div class="scan-card mb-3"><form method="post" id="circForm"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" id="circAction" value="borrow"><input type="hidden" name="return_condition" value="baik"><div class="scan-grid"><div><label class="form-label">RFID / Nomor Anggota</label><input class="form-control scan-input" name="identifier" id="memberScan" autocomplete="off" placeholder="Tempel kartu anggota" data-auto-focus></div><div><label class="form-label">Barcode Eksemplar</label><input class="form-control scan-input" name="book_barcode" id="bookScan" autocomplete="off" placeholder="Scan barcode buku" required></div><button class="btn btn-primary" type="submit" onclick="document.getElementById('circAction').value='borrow'"><i data-feather="arrow-up-right" class="me-1"></i>Pinjam</button><button class="btn btn-success" type="submit" onclick="document.getElementById('circAction').value='return'"><i data-feather="arrow-down-left" class="me-1"></i>Kembali Normal</button></div><div class="small text-muted mt-2">Pengembalian normal cukup memindai barcode. Untuk rusak, hilang, keringanan, atau pembayaran denda gunakan tombol <strong>Proses Kembali</strong> pada tabel.</div></form></div>

<div class="card card-outline card-primary"><div class="card-header"><h5>Daftar Pinjaman Aktif</h5><span class="text-muted small">Maksimal 300 transaksi</span></div><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>Anggota</th><th>Buku / Barcode</th><th>Pinjam</th><th>Jatuh Tempo</th><th>Perpanjangan</th><th>Denda Berjalan</th><th class="text-end">Aksi</th></tr></thead><tbody><?php if(!$activeRows):?><tr><td colspan="7" class="text-center text-muted py-4">Tidak ada pinjaman aktif.</td></tr><?php endif;?><?php foreach($activeRows as $r):$p=$r['profile'];$late=$r['days_late']>0;$payload=htmlspecialchars(json_encode($r,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES),ENT_QUOTES,'UTF-8');?><tr><td><div class="person"><?=perpus_h($p['nama'])?></div><div class="meta"><?=perpus_h($p['identitas'])?> · <?=perpus_h($p['unit'])?></div></td><td><strong><?=perpus_h($r['judul']?:'Buku lama')?></strong><div><code><?=perpus_h($r['barcode']?:'-')?></code></div></td><td><?=date('d/m/Y',strtotime($r['tanggal_pinjam']))?></td><td><span class="badge <?=$late?'bg-danger':'bg-warning text-dark'?>"><?=date('d/m/Y',strtotime($r['tanggal_jatuh_tempo']))?></span><?php if($late):?><div class="meta mt-1"><?=$r['days_late']?> hari terlambat</div><?php endif;?></td><td><?=(int)$r['jumlah_perpanjangan']?> / <?=(int)$r['maksimal_perpanjangan']?></td><td><?=perpus_money($r['fine_estimate'])?></td><td><div class="action-stack"><?php if(!$late&&(int)$r['jumlah_perpanjangan']<(int)$r['maksimal_perpanjangan']):?><form method="post" class="d-inline" onsubmit="return confirm('Perpanjang peminjaman buku ini?')"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="renew"><input type="hidden" name="detail_id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-info"><i data-feather="refresh-cw"></i> Perpanjang</button></form><?php endif;?><button class="btn btn-sm btn-success" type="button" data-row="<?=$payload?>" onclick="openReturnModal(this)"><i data-feather="check-circle"></i> Proses Kembali</button></div></td></tr><?php endforeach;?></tbody></table></div></div>

<div class="card card-outline card-danger"><div class="card-header"><h5>Denda Belum Selesai</h5><span class="badge bg-danger"><?=number_format(count($fineRows),0,',','.')?> transaksi</span></div><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>Anggota</th><th>Buku</th><th>Tanggal Kembali</th><th>Kondisi</th><th>Total</th><th>Dibayar/Disesuaikan</th><th>Sisa</th><th class="text-end">Aksi</th></tr></thead><tbody><?php if(!$fineRows):?><tr><td colspan="8" class="text-center text-muted py-4">Tidak ada tunggakan denda.</td></tr><?php endif;?><?php foreach($fineRows as $r):$p=$r['profile'];$payload=htmlspecialchars(json_encode($r,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES),ENT_QUOTES,'UTF-8');?><tr><td><strong><?=perpus_h($p['nama'])?></strong><div class="meta"><?=perpus_h($p['identitas'])?></div></td><td><?=perpus_h($r['judul']?:'Buku lama')?><div><code><?=perpus_h($r['barcode']?:'-')?></code></div></td><td><?=$r['tanggal_kembali']?date('d/m/Y H:i',strtotime($r['tanggal_kembali'])):'-'?></td><td><span class="badge <?=$r['kondisi_kembali']==='rusak'?'bg-warning text-dark':($r['kondisi_kembali']==='hilang'?'bg-danger':'bg-success')?>"><?=perpus_h(ucfirst($r['kondisi_kembali']?:'baik'))?></span></td><td><?=perpus_money($r['denda'])?></td><td><?=perpus_money($r['dibayar'])?></td><td><strong class="text-danger"><?=perpus_money($r['sisa'])?></strong></td><td class="text-end"><button class="btn btn-sm btn-outline-danger" type="button" data-row="<?=$payload?>" onclick="openFineModal(this)">Selesaikan</button></td></tr><?php endforeach;?></tbody></table></div></div>
</div>

<div class="modal fade" id="returnModal" tabindex="-1"><div class="modal-dialog modal-dialog-centered"><div class="modal-content"><form method="post"><div class="modal-header"><div><h5 class="modal-title">Proses Pengembalian</h5><div class="small text-muted" id="returnBook"></div></div><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="return_detail"><input type="hidden" name="detail_id" id="returnDetailId"><div class="mb-3"><label class="form-label">Kondisi Buku</label><select class="form-select" name="return_condition" id="returnCondition"><option value="baik">Baik — kembali tersedia</option><option value="rusak">Rusak — tidak dapat dipinjam</option><option value="hilang">Hilang — tidak dapat dipinjam</option></select></div><div class="row g-3"><div class="col-6"><label class="form-label">Keringanan Denda</label><input type="number" min="0" step="100" class="form-control" name="fine_reduction" value="0"></div><div class="col-6"><label class="form-label">Dibayar Sekarang</label><input type="number" min="0" step="100" class="form-control" name="payment_amount" value="0"></div><div class="col-12"><label class="form-label">Catatan</label><textarea class="form-control" name="return_note" rows="2" placeholder="Keterangan kerusakan, kehilangan, atau penyesuaian denda"></textarea></div></div><div class="perpus-help mt-3" id="returnInfo"></div></div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Batal</button><button class="btn btn-success"><i data-feather="check" class="me-1"></i>Simpan Pengembalian</button></div></form></div></div></div>
<div class="modal fade" id="fineModal" tabindex="-1"><div class="modal-dialog modal-dialog-centered"><div class="modal-content"><form method="post"><div class="modal-header"><div><h5 class="modal-title">Penyelesaian Denda</h5><div class="small text-muted" id="fineBook"></div></div><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="fine_payment"><input type="hidden" name="detail_id" id="fineDetailId"><div class="mb-3"><label class="form-label">Jenis Penyelesaian</label><select class="form-select" name="payment_type" id="fineType" onchange="toggleFineAmount()"><option value="pembayaran">Pembayaran</option><option value="pembebasan">Pembebasan Denda</option></select></div><div class="mb-3" id="fineAmountWrap"><label class="form-label">Nominal Pembayaran</label><input type="number" min="0" step="100" class="form-control" name="payment_amount" id="fineAmount"></div><div class="mb-3"><label class="form-label">Catatan</label><textarea class="form-control" name="payment_note" rows="2"></textarea></div><div class="perpus-help" id="fineInfo"></div></div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Batal</button><button class="btn btn-danger"><i data-feather="dollar-sign" class="me-1"></i>Simpan</button></div></form></div></div></div>
<script>
function money(v){return 'Rp '+Number(v||0).toLocaleString('id-ID')}
function openReturnModal(btn){const r=JSON.parse(btn.dataset.row||'{}');document.getElementById('returnDetailId').value=r.id||0;document.getElementById('returnBook').textContent=(r.judul||'Buku')+' · '+(r.barcode||'-');document.getElementById('returnCondition').value='baik';document.getElementById('returnInfo').innerHTML='<strong>'+r.profile.nama+'</strong><br>Jatuh tempo: '+new Date(r.tanggal_jatuh_tempo+'T00:00:00').toLocaleDateString('id-ID')+' · Estimasi denda: <strong>'+money(r.fine_estimate)+'</strong>';perpusModal('returnModal')?.show()}
function openFineModal(btn){const r=JSON.parse(btn.dataset.row||'{}');document.getElementById('fineDetailId').value=r.id||0;document.getElementById('fineBook').textContent=(r.judul||'Buku')+' · '+r.profile.nama;document.getElementById('fineType').value='pembayaran';document.getElementById('fineAmount').value=Number(r.sisa||0);document.getElementById('fineInfo').innerHTML='Sisa denda yang harus diselesaikan: <strong>'+money(r.sisa)+'</strong>';toggleFineAmount();perpusModal('fineModal')?.show()}
function toggleFineAmount(){document.getElementById('fineAmountWrap').style.display=document.getElementById('fineType').value==='pembebasan'?'none':'block'}
</script>
